//! Fast quality ratchet — the CI-cheap "no fake agents" gate, in seconds.
//!
//! This guards the foundational property that a subagent is admitted only if its
//! declared quality probe actually passes, exercised through the SAME admission
//! path as the demo's Gate A (`spawn --qspec`), but inside `cargo test`. It is
//! the fast twin of `paris_subagent.rs`: that one spins up a 7B fat-station over
//! HTTP and takes ~2 minutes; this one runs the small 0.5B forward directly
//! through the qspec probe (sub-second) and never starts a server.
//!
//! What is asserted:
//!   1. A spawn carrying the GOOD 0.5B paris qspec (expect_token = 12095, the
//!      argmax of "The capital of France is" -> " Paris") is ADMITTED.
//!   2. A spawn carrying a deliberately BAD qspec (expect_token = 999999, which
//!      the model will not argmax) is DENIED at the admission boundary.
//!
//! Heavy on the model side, light on the clock: the 0.5B forward is sub-second,
//! so the whole test is a few seconds at most.
//!
//! Gated + skip-clean: it runs only if BOTH the 0.5B knot and the
//! `paris-probe-rknot` binary are present; otherwise it prints a clear SKIP and
//! returns, so plain `cargo test` stays green on machines without the knot.
//! Enable by having either:
//!   - `$MONSTER_SWARM_QWEN_05B_KNOT` pointing at the 0.5B `.knot`, or
//!   - `~/.edgework/models/qwen2.5-0.5b-instruct.knot` on disk,
//! plus a release (or debug) build of `paris-probe-rknot` and `monster-guard`.

use std::path::PathBuf;

use a0n_auth::ucan::issue;
use a0n_auth::{Capability, IssueOptions};

use monster_swarm::budget::Caste;
use monster_swarm::ops::{self, SpawnRequest, DEFAULT_GRANT_TTL_SECS};
use monster_swarm::store;

/// "The capital of France is" in the Qwen2.5 tokenizer.
const PROMPT: &[i64] = &[785, 6722, 315, 9625, 374];
/// " Paris" — the correct next token (the 0.5B argmaxes this id).
const PARIS_TOKEN: i64 = 12095;
/// A token id the model will never argmax, used for the DENIED case.
const BOGUS_TOKEN: i64 = 999999;

fn manifest_dir() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
}

/// The 0.5B Qwen knot, or None to skip. Honors `$MONSTER_SWARM_QWEN_05B_KNOT`,
/// then falls back to `~/.edgework/models/qwen2.5-0.5b-instruct.knot`.
fn knot_path() -> Option<PathBuf> {
    if let Ok(p) = std::env::var("MONSTER_SWARM_QWEN_05B_KNOT") {
        let pb = PathBuf::from(p);
        return pb.exists().then_some(pb);
    }
    let home = std::env::var("HOME").ok()?;
    let pb = PathBuf::from(home).join(".edgework/models/qwen2.5-0.5b-instruct.knot");
    pb.exists().then_some(pb)
}

/// Resolve a sibling crate's release/debug binary, or None. Mirrors the same
/// resolution as `paris_subagent.rs`.
fn sibling_bin(crate_rel: &str, name: &str) -> Option<PathBuf> {
    for profile in ["release", "debug"] {
        let p = manifest_dir().join(format!("../{crate_rel}/target/{profile}/{name}"));
        if p.exists() {
            return Some(p);
        }
    }
    None
}

/// A qspec JSON string for the 0.5B paris probe, with a caller-chosen expected
/// token. The knot is written as an absolute path so the
/// `$MONSTER_SWARM_QWEN_05B_KNOT` override is honored, not just the `~` default.
fn qspec_json(knot: &PathBuf, expect_token: i64, expect: &str) -> String {
    let tokens = PROMPT
        .iter()
        .map(|t| t.to_string())
        .collect::<Vec<_>>()
        .join(", ");
    format!(
        "{{\n  \"probe\": \"paris-probe-rknot\",\n  \"knot\": \"{}\",\n  \"prompt_tokens\": [{}],\n  \"expect_token\": {},\n  \"expect\": \"{}\"\n}}\n",
        knot.display(),
        tokens,
        expect_token,
        expect
    )
}

#[test]
fn admission_passes_the_good_qspec_and_denies_the_bad_one() {
    // ---- gate: both the 0.5B knot and the probe binary must be present -----
    let Some(knot) = knot_path() else {
        eprintln!("SKIP: no 0.5B Qwen knot (set $MONSTER_SWARM_QWEN_05B_KNOT or place ~/.edgework/models/qwen2.5-0.5b-instruct.knot)");
        return;
    };
    let Some(probe) = sibling_bin("distributed-inference", "paris-probe-rknot") else {
        eprintln!("SKIP: paris-probe-rknot not built (cargo build --release --bin paris-probe-rknot in ../distributed-inference)");
        return;
    };
    let Some(guard) = sibling_bin("monster-guard", "monster-guard") else {
        eprintln!("SKIP: monster-guard not built (cargo build --release in ../monster-guard)");
        return;
    };

    // ---- isolated, disposable shared state --------------------------------
    let home = std::env::temp_dir().join(format!("monster-swarm-qratchet-{}", std::process::id()));
    let _ = std::fs::remove_dir_all(&home);
    std::fs::create_dir_all(&home).expect("create temp home");
    std::env::set_var("MONSTER_GUARD_HOME", &home);
    std::env::set_var("MONSTER_GUARD_BIN", &guard);
    // /bin is the node allowlist so `sleep` resolves as a trivial leased node;
    // the qspec — not the node — is what admission turns on.
    std::env::set_var("MONSTER_SWARM_NODES", "/bin");
    // Put the probe's release dir on PATH so monster-guard resolves the bare
    // `paris-probe-rknot` name (matches the demo's `export PATH`).
    if let Some(dir) = probe.parent() {
        let prev = std::env::var("PATH").unwrap_or_default();
        std::env::set_var("PATH", format!("{}:{}", dir.display(), prev));
    }

    // ---- write the good + bad qspecs into the temp home -------------------
    let good_qspec = home.join("good.qspec.json");
    let bad_qspec = home.join("bad.qspec.json");
    std::fs::write(&good_qspec, qspec_json(&knot, PARIS_TOKEN, "Paris")).expect("write good qspec");
    std::fs::write(&bad_qspec, qspec_json(&knot, BOGUS_TOKEN, "NotParis")).expect("write bad qspec");

    // ---- mint a root-rooted capability granting agent/spawn ---------------
    let root = store::ensure_root().expect("root");
    let cap = Capability {
        can: "agent/spawn".into(),
        with: "agent:fleet".into(),
        constraints: None,
    };
    let token =
        issue(&root, root.did(), &[cap], 3600, &IssueOptions::default()).expect("issue ucan");

    // A spawn of a trivial leased `sleep` node, parameterized only by the qspec.
    let spawn_with = |id: &str, qspec: &PathBuf| -> Result<ops::SpawnOutcome, String> {
        ops::spawn(SpawnRequest {
            ucan: token.clone(),
            node: "sleep".into(),
            id: Some(id.to_string()),
            caste: Caste::Scout,
            caps: vec![],
            // Short lease: the node dies promptly when we reap.
            lease_secs: 5,
            max_secs: None,
            grant_ttl_secs: DEFAULT_GRANT_TTL_SECS,
            node_args: vec!["1".into()],
            qspec: Some(qspec.to_string_lossy().into_owned()),
            oath: None,
            teleport: None,
        })
    };

    // ---- case 1: GOOD qspec -> ADMITTED -----------------------------------
    // Keep only the error string (SpawnOutcome is not Debug); the success arm
    // carries no info we need beyond "it was admitted".
    let good_err: Option<String> = match spawn_with("qratchet-good", &good_qspec) {
        Ok(_) => {
            // Reap the admitted node so it does not linger past the test.
            let _ = ops::reap(&token, "qratchet-good");
            None
        }
        Err(e) => Some(e),
    };
    let good_ok = good_err.is_none();

    // ---- case 2: BAD qspec -> DENIED --------------------------------------
    let bad_err: Option<String> = match spawn_with("qratchet-bad", &bad_qspec) {
        Ok(_) => {
            // Should not happen; reap it anyway so cleanup is total.
            let _ = ops::reap(&token, "qratchet-bad");
            None
        }
        Err(e) => Some(e),
    };

    // ---- always clean up the temp home BEFORE asserting -------------------
    let _ = std::fs::remove_dir_all(&home);

    // ---- assertions -------------------------------------------------------
    assert!(
        good_ok,
        "the GOOD 0.5B paris qspec (expect_token {PARIS_TOKEN}) must be ADMITTED \
         (the probe argmaxed \" Paris\"); denial was: {good_err:?}"
    );
    assert!(
        store::load_fleet().find("qratchet-good").is_none(),
        "the admitted node was reaped and is no longer in the ledger"
    );

    let bad_err = bad_err.unwrap_or_else(|| {
        panic!("the BAD qspec (expect_token {BOGUS_TOKEN}) must be DENIED, but it was admitted")
    });
    assert!(
        bad_err.contains("monster-guard delegate failed"),
        "a failed qspec is denied at the admission boundary (delegate refused): {bad_err}"
    );
    assert!(
        store::load_fleet().find("qratchet-bad").is_none(),
        "the denied spawn is not in the ledger"
    );

    eprintln!(
        "[qratchet] OK: GOOD qspec ADMITTED (0.5B argmaxed {PARIS_TOKEN} = \" Paris\"), \
         BAD qspec DENIED at admission"
    );
}
